import { useState, useEffect, useRef } from 'react';
import { getConversation, deleteMessage } from '../../services/api';
import { useSocket } from '../../context/SocketContext';
import { useAuth } from '../../context/AuthContext';
import MessageInput from './MessageInput';
import { formatDistanceToNow } from 'date-fns';

export default function ChatWindow({ contact }) {
  const [messages, setMessages] = useState([]);
  const [typing, setTyping] = useState(false);
  const bottomRef = useRef(null);
  const { socket } = useSocket();
  const { user } = useAuth();

  useEffect(() => {
    if (!contact) return;
    getConversation(contact.id).then(res => setMessages(res.data));
    socket?.emit('join_dm', { userId: contact.id });
  }, [contact?.id]);

  useEffect(() => {
    const handler = (msg) => {
      if (
        (msg.senderId === contact?.id && msg.recipientId === user?.id) ||
        (msg.senderId === user?.id && msg.recipientId === contact?.id)
      ) {
        setMessages(prev => [...prev, msg]);
      }
    };
    const typingHandler = ({ userId }) => { if (userId === contact?.id) setTyping(true); };
    const stopTypingHandler = ({ userId }) => { if (userId === contact?.id) setTyping(false); };
    const deleteHandler = ({ id, forEveryone }) => {
      if (forEveryone) setMessages(prev => prev.map(m => m.id === id ? { ...m, deletedForEveryone: true, content: 'This message was deleted' } : m));
    };

    socket?.on('new_message', handler);
    socket?.on('typing', typingHandler);
    socket?.on('stop_typing', stopTypingHandler);
    socket?.on('message_deleted', deleteHandler);
    return () => {
      socket?.off('new_message', handler);
      socket?.off('typing', typingHandler);
      socket?.off('stop_typing', stopTypingHandler);
      socket?.off('message_deleted', deleteHandler);
    };
  }, [socket, contact?.id, user?.id]);

  useEffect(() => { bottomRef.current?.scrollIntoView({ behavior: 'smooth' }); }, [messages]);

  const handleDelete = async (id, forEveryone) => {
    await deleteMessage(id, forEveryone);
    if (forEveryone) setMessages(prev => prev.map(m => m.id === id ? { ...m, deletedForEveryone: true, content: 'This message was deleted' } : m));
  };

  const handleSend = (msg) => setMessages(prev => [...prev, msg]);

  if (!contact) return (
    <div className="chat-empty">
      <div className="chat-empty-icon">💬</div>
      <h3>Select a conversation</h3>
      <p>Choose someone to start chatting</p>
    </div>
  );

  return (
    <div className="chat-window">
      <div className="chat-header">
        <div className="chat-avatar">{contact.displayName?.[0]}</div>
        <div className="chat-header-info">
          <h3>{contact.displayName || contact.username}</h3>
          <span className={contact.isOnline ? 'status-online' : 'status-offline'}>
            {contact.isOnline ? '● Online' : `Last seen ${formatDistanceToNow(new Date(contact.lastSeen), { addSuffix: true })}`}
          </span>
        </div>
        <div className="chat-header-actions">
          <button className="icon-btn" title="Voice Call">📞</button>
          <button className="icon-btn" title="Video Call">📹</button>
          <button className="icon-btn" title="Search">🔍</button>
        </div>
      </div>

      <div className="messages-container">
        {messages.map(msg => (
          <div key={msg.id} className={`message-row ${msg.senderId === user?.id ? 'outgoing' : 'incoming'}`}>
            <div className="message-bubble-wrap">
              {msg.senderId !== user?.id && (
                <div className="msg-sender-name">{msg.sender?.displayName}</div>
              )}
              <div className={`message-bubble ${msg.deletedForEveryone ? 'deleted' : ''}`}>
                {msg.deletedForEveryone ? <em>🚫 This message was deleted</em> : msg.content}
              </div>
              <div className="message-meta">
                <span className="message-time">
                  {new Date(msg.createdAt).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                </span>
                {msg.senderId === user?.id && !msg.deletedForEveryone && (
                  <span className="message-actions">
                    <button onClick={() => handleDelete(msg.id, false)}>Delete for me</button>
                    <button onClick={() => handleDelete(msg.id, true)}>Delete for everyone</button>
                  </span>
                )}
              </div>
            </div>
          </div>
        ))}
        {typing && (
          <div className="message-row incoming">
            <div className="typing-bubble">
              <span/><span/><span/>
            </div>
          </div>
        )}
        <div ref={bottomRef} />
      </div>

      <MessageInput recipientId={contact.id} onSent={handleSend} />
    </div>
  );
}
